client_script:
frappe.web_form.on('load', function(){
  var user = (frappe.session && frappe.session.user) ? frappe.session.user : null;
  if (!user || user === 'Guest') return;

  var roles = (frappe.boot && frappe.boot.user && frappe.boot.user.roles) ? frappe.boot.user.roles : [];
  var can_select_any_employee = roles.indexOf('HR Manager') !== -1 || roles.indexOf('Responsable RH') !== -1 || roles.indexOf('HR User') !== -1 || roles.indexOf('System Manager') !== -1;

  if (!frappe.web_form.doc.posting_date) {
    frappe.web_form.set_value('posting_date', frappe.datetime.get_today());
  }

  // Gate signatures by workflow_state + role
  var doc = frappe.web_form.doc || {};
  var state = doc.workflow_state || 'Brouillon';
  var sig_rules = {
    'signature_employe_la': { states: ['Brouillon', 'Draft'], roles: [] },
    'signature_superieur_la': { states: ['En attente Chef', 'En attente Sup\u00e9rieur'], roles: ['Sup\u00e9rieur Imm\u00e9diat','Chef Service','System Manager'] },
    'signature_rh_la': { states: ['En attente RH'], roles: ['Responsable RH','HR Manager','HR User','System Manager'] },
    'signature_dg_la': { states: ['En attente DG'], roles: ['Directeur G\u00e9n\u00e9ral','DG','System Manager'] }
  };
  Object.keys(sig_rules).forEach(function(f){
    var r = sig_rules[f];
    var stateOk = r.states.indexOf(state) !== -1;
    var roleOk = r.roles.length === 0 || r.roles.some(function(rr){ return roles.indexOf(rr) !== -1; });
    if (stateOk && roleOk) frappe.web_form.set_df_property(f, 'read_only', 0);
  });

  frappe.call({
    method: 'frappe.client.get_value',
    args: {
      doctype: 'Employee',
      filters: { user_id: user, status: 'Active' },
      fieldname: ['name', 'employee_name', 'department']
    },
    callback: function(r){
      if (!r || !r.message) return;
      if (!frappe.web_form.doc.employee) {
        frappe.web_form.set_value('employee', r.message.name);
      }
      if (!frappe.web_form.doc.employee_name && r.message.employee_name) {
        frappe.web_form.set_value('employee_name', r.message.employee_name);
      }
      if (!frappe.web_form.doc.department && r.message.department) {
        frappe.web_form.set_value('department', r.message.department);
      }
      if (!can_select_any_employee) {
        frappe.web_form.set_df_property('employee', 'read_only', 1);
      }

      setTimeout(function() {
        if (window.kyaRestructureForm) window.kyaRestructureForm();
      }, 150);
    }
  });
});
